import numpy as np
from langchain_openai import OpenAIEmbeddings

embedder = OpenAIEmbeddings(model="text-embedding-3-small")

# Representative anchor phrases per datasource
ANCHORS = {
    "vector_store": [
        "what does the policy say about",
        "explain the concept of",
        "how does the system handle",
    ],
    "sql_database": [
        "how many records",
        "what is the total count of",
        "list all users who",
    ],
    "web_search": [
        "what happened today",
        "latest news about",
        "current status of",
    ],
}

# Pre-compute anchor embeddings once at startup
anchor_embeddings: dict[str, np.ndarray] = {}
for source, phrases in ANCHORS.items():
    vecs = np.array(embedder.embed_documents(phrases))
    anchor_embeddings[source] = vecs.mean(axis=0)  # centroid


def cosine_sim(a: np.ndarray, b: np.ndarray) -> float:
    return float(np.dot(a, b) / (np.linalg.norm(a) * np.linalg.norm(b) + 1e-9))


def route_by_embedding(question: str) -> str:
    q_vec = np.array(embedder.embed_query(question))
    scores = {
        source: cosine_sim(q_vec, centroid)
        for source, centroid in anchor_embeddings.items()
    }
    return max(scores, key=scores.get)


print(route_by_embedding("How many customers signed up last week?"))
