from typing import TypedDict
from langgraph.graph import StateGraph, END

class RouterState(TypedDict):
    question: str
    datasource: str
    context: str
    answer: str


def route_node(state: RouterState) -> RouterState:
    decision = classify_query(state["question"])
    return {**state, "datasource": decision.datasource}


def vector_node(state: RouterState) -> RouterState:
    docs = retriever.invoke(state["question"])
    return {**state, "context": "\n\n".join(d.page_content for d in docs)}


def sql_node(state: RouterState) -> RouterState:
    result = run_sql_query(state["question"])
    return {**state, "context": result}


def web_node(state: RouterState) -> RouterState:
    results = TavilySearchResults(max_results=3).invoke(state["question"])
    return {**state, "context": "\n".join(r["content"] for r in results)}


def generate_node(state: RouterState) -> RouterState:
    answer = answer_chain.invoke({"context": state["context"], "question": state["question"]})
    return {**state, "answer": answer}


def select_source(state: RouterState) -> str:
    return state["datasource"]


graph = StateGraph(RouterState)
graph.add_node("route",    route_node)
graph.add_node("vector",   vector_node)
graph.add_node("sql",      sql_node)
graph.add_node("web",      web_node)
graph.add_node("generate", generate_node)

graph.set_entry_point("route")
graph.add_conditional_edges("route", select_source, {
    "vector_store":    "vector",
    "sql_database":    "sql",
    "web_search":      "web",
    "knowledge_graph": "vector",  # fallback to vector for now
})
for src in ("vector", "sql", "web"):
    graph.add_edge(src, "generate")
graph.add_edge("generate", END)

router_app = graph.compile()
result = router_app.invoke({"question": "What is the return policy for electronics?"})
print(result["datasource"], "→", result["answer"][:80])

from typing import Optional

def safe_route_and_retrieve(question: str, fallback_retriever) -> str:
    """Route with a fallback to vector search if primary source fails."""
    try:
        decision = classify_query(question)
        datasource = decision.datasource

        if datasource == "sql_database":
            context = run_sql_query(question)
            if not context or context.strip() == "":
                raise ValueError("SQL returned empty result")
        elif datasource == "web_search":
            results = TavilySearchResults(max_results=3).invoke(question)
            context = "\n".join(r["content"] for r in results)
        else:
            docs = fallback_retriever.invoke(question)
            context = "\n\n".join(d.page_content for d in docs)

        return answer_chain.invoke({"context": context, "question": question})

    except Exception as exc:
        # Log the failure and fall back to vector search
        import logging
        logging.warning("Routing failed for '%s': %s — falling back to vector", question, exc)
        docs = fallback_retriever.invoke(question)
        context = "\n\n".join(d.page_content for d in docs)
        return answer_chain.invoke({"context": context, "question": question})

eval_set = [
    {"question": "What is the refund policy?",             "expected": "vector_store"},
    {"question": "How many orders were placed yesterday?", "expected": "sql_database"},
    {"question": "What happened in AI news this week?",    "expected": "web_search"},
    {"question": "Who manages the engineering team?",      "expected": "knowledge_graph"},
]

def evaluate_router(eval_set: list[dict]) -> dict:
    correct = 0
    errors = []
    for item in eval_set:
        decision = classify_query(item["question"])
        if decision.datasource == item["expected"]:
            correct += 1
        else:
            errors.append({
                "question": item["question"],
                "expected": item["expected"],
                "got": decision.datasource,
                "reason": decision.reason,
            })
    accuracy = correct / len(eval_set) * 100
    return {"accuracy": round(accuracy, 1), "n": len(eval_set), "errors": errors}

report = evaluate_router(eval_set)
print(f"Router accuracy: {report['accuracy']}% ({report['n']} queries)")
for err in report["errors"]:
    print(f"  MISROUTE: '{err['question']}' → {err['got']} (expected {err['expected']})")
